DOCUMENT();
############################################################ # Load Macros ############################################################ loadMacros( "PGstandard.pl", "PGML.pl", "AnswerFormatHelp.pl", "PCCmacros.pl", "parserNumberWithUnits.pl", "parserLinearRelation.pl", "PGcourse.pl", ); COMMENT('Authored in PreTeXt');
############################################################ # Header ############################################################ TEXT(beginproblem());
############################################################ # PG Setup Code ############################################################ $initial = 100; $start = NumberWithUnits("$initial lb"); $rate = random(7,12); $speed = NumberWithUnits("$rate lb"); $final = random(20,30,5); $end = NumberWithUnits("$final lb"); Context("LinearRelation")->variables->are(t => 'Real'); $equation = LinearRelation("$initial - $rate t = $final");
############################################################ # Body ############################################################
BEGIN_PGML Write an equation to model the scenario. There is no need to solve the equation.
A restaurant stocks its pantry with [`[$start]`] of onions. When the supply reaches [`[$end]\text{,}`] it's time to order more. Recently, the restaurant has been using [`[$speed]`] of onions per day. How long since restocking will it take until another order must be placed? Write an equation to model this scenario. There is no need to solve it.
[@KeyboardInstructions('Use [|t|]* as the variable.')@]**
[_]{$equation}{20}
END_PGML
